function which(cmd) {
  try {
    const r = spawnSync(process.platform === 'win32' ? 'where' : 'which', [cmd], { encoding: 'utf8' });
    if (r.status === 0) return r.stdout.split(/\r?\n/)[0].trim();
  } catch (_) {}
  return null;
}
const YTDLP  = which('yt-dlp') || which('yt-dlp.exe');
const FFMPEG = which('ffmpeg') || which('ffmpeg.exe');
if (!YTDLP)  log.warn('yt-dlp не найден в PATH — поиск/стриминг работать не будет. Установите: pip install -U yt-dlp');
