const settingsGet  = db.prepare('SELECT value FROM settings WHERE key = ?');
const settingsPut  = db.prepare('INSERT INTO settings(key, value) VALUES(?, ?) ON CONFLICT(key) DO UPDATE SET value=excluded.value');
function setting(key, def = null) {
  const r = settingsGet.get(key);
  return r ? r.value : def;
}
function setSetting(key, value) {
  settingsPut.run(key, String(value));
}
