// ── upsertUser helper
function upsertUser({ tg_id, username, first_name, photo_url = null }) {
  let row = Q.userByTg.get(tg_id);
  if (!row) {
    Q.insertUser.run(tg_id, username || null, first_name || null, photo_url);
    row = Q.userByTg.get(tg_id);
  } else {
    Q.updateUserMeta.run(username || row.username, first_name || row.first_name, photo_url, tg_id);
    row = Q.userByTg.get(tg_id);
  }
  return row;
}

// ════════════════════════════════════════════════════════════════════════
//  TELEGRAM WEB-APP initData валидация
//  https://core.telegram.org/bots/webapps#validating-data-received-via-the-mini-app
// ════════════════════════════════════════════════════════════════════════
function parseInitData(initData) {
  if (!initData || typeof initData !== 'string') return null;
  const url = new URLSearchParams(initData);
  const hash = url.get('hash');
  if (!hash) return null;
  url.delete('hash');
  const pairs = [];
  for (const [k, v] of url.entries()) pairs.push(`${k}=${v}`);
  pairs.sort();
  const dataCheckString = pairs.join('\n');
  const secret = crypto.createHmac('sha256', 'WebAppData').update(BOT_TOKEN).digest();
  const calc   = crypto.createHmac('sha256', secret).update(dataCheckString).digest('hex');
  if (calc !== hash) return null;
  const authDate = parseInt(url.get('auth_date') || '0', 10);
  // initData валиден 24 часа
  if (Date.now() / 1000 - authDate > 86400) return null;
  let user = null;
  try { user = JSON.parse(url.get('user') || 'null'); } catch (_) { user = null; }
  if (!user || !user.id) return null;
  return { user, auth_date: authDate };
}

// ════════════════════════════════════════════════════════════════════════
//  YT-DLP — поиск / получение аудио-URL / метадата
// ════════════════════════════════════════════════════════════════════════
const SEARCH_TTL_SEC = 60 * 60; // 1 час

function ytdlpSpawn(args, timeoutMs = 30000) {
  return new Promise((resolve, reject) => {
    if (!YTDLP) return reject(new Error('yt-dlp not installed'));
    const child = spawn(YTDLP, args, { stdio: ['ignore', 'pipe', 'pipe'] });
    let out = '', err = '';
    const t = setTimeout(() => { try { child.kill('SIGKILL'); } catch (_) {} reject(new Error('yt-dlp timeout')); }, timeoutMs);
    child.stdout.on('data', d => { out += d.toString(); });
    child.stderr.on('data', d => { err += d.toString(); });
    child.on('error', e => { clearTimeout(t); reject(e); });
    child.on('close', code => {
      clearTimeout(t);
      if (code === 0) resolve(out);
      else reject(new Error(`yt-dlp exit ${code}: ${err.slice(0, 400)}`));
    });
  });
}

function bestThumb(item) {
  const tt = item.thumbnails || item.thumbnail || [];
  if (typeof tt === 'string') return tt;
  if (Array.isArray(tt) && tt.length) {
    // выбираем самую большую
    const sorted = [...tt].sort((a, b) => (b.width || 0) - (a.width || 0));
    return sorted[0].url || sorted[0];
  }
  return null;
}

function normalizeTrack(item) {
  if (!item) return null;
  const id = item.id || item.videoId || item.url;
  if (!id) return null;
  let performer = item.artist || item.uploader || item.channel || 'Unknown';
  let title = item.title || 'Unknown';
  // featured-артисты: пытаемся вытащить из заголовка (feat. / ft. / с )
  const featured = [];
  const m = title.match(/\(?\s*(?:feat\.?|ft\.?|с участием)\s+([^)]+?)\s*\)?\s*$/i);
  if (m) {
    featured.push(...m[1].split(/[,&]| и /).map(s => s.trim()).filter(Boolean));
  }
  return {
    video_id:  id,
    title,
    performer,
    duration:  parseInt(item.duration || 0, 10) || 0,
    thumbnail: bestThumb(item),
    album:     item.album || null,
    featured,
  };
}

async function ytSearch(query, count = 10) {
  const q = `${query}`.trim().toLowerCase();
  if (!q) return [];
  const nowSec = Math.floor(Date.now() / 1000);
  const cached = Q.searchGet.get(q, nowSec - SEARCH_TTL_SEC);
  if (cached) {
    try { return JSON.parse(cached.data).slice(0, count); } catch (_) {}
  }
  // yt-dlp поиск (music.youtube.com → YouTube Music)
  const args = [
    `ytsearch${count + 5}:${query}`,
    '--default-search', 'ytsearch',
    '-J',                       // dump-single-json
    '--no-warnings',
    '--skip-download',
    '--no-playlist',
    '--flat-playlist',
    '--extractor-args', 'youtube:player_client=web_music',
  ];
  let raw;
  try {
    raw = await ytdlpSpawn(args, 25000);
  } catch (e) {
    log.warn('ytSearch fail:', e.message);
    return [];
  }
  let json;
  try { json = JSON.parse(raw); } catch (_) { return []; }
  const entries = (json && json.entries) || [];
  const items = entries.map(normalizeTrack).filter(Boolean).slice(0, count);
  // Сохраним треки в БД для быстрого доступа
  for (const t of items) {
    Q.upsertTrack.run(t.video_id, t.title, t.performer, t.duration, t.thumbnail,
                      t.album, JSON.stringify(t.featured || []));
  }
  try { Q.searchPut.run(q, JSON.stringify(items), nowSec); } catch (_) {}
  return items;
}

// Кеш direct-audio-URL: они истекают, поэтому 30 мин достаточно
const audioUrlCache = new Map(); // video_id -> { url, exp }

async function getAudioUrl(videoId) {
  const cached = audioUrlCache.get(videoId);
  if (cached && cached.exp > Date.now()) return cached.url;
  const args = [
    `https://music.youtube.com/watch?v=${videoId}`,
    '-f', 'bestaudio[ext=m4a]/bestaudio',
    '--get-url',
    '--no-warnings',
    '--no-playlist',
    '--extractor-args', 'youtube:player_client=web_music',
  ];
  const out = (await ytdlpSpawn(args, 25000)).trim().split(/\r?\n/).filter(Boolean);
  if (!out.length) throw new Error('audio URL not found');
  const url = out[out.length - 1];
  audioUrlCache.set(videoId, { url, exp: Date.now() + 25 * 60 * 1000 });
  return url;
}

async function getTrackMetaFromYt(videoId) {
  const args = [
    `https://music.youtube.com/watch?v=${videoId}`,
    '-J', '--no-warnings', '--skip-download', '--no-playlist',
    '--extractor-args', 'youtube:player_client=web_music',
  ];
  const out = await ytdlpSpawn(args, 25000);
  const j = JSON.parse(out);
  const t = normalizeTrack(j);
  if (t) {
    Q.upsertTrack.run(t.video_id, t.title, t.performer, t.duration, t.thumbnail,
                      t.album, JSON.stringify(t.featured || []));
  }
  return t;
}

// ════════════════════════════════════════════════════════════════════════
//  LRCLIB.NET — синхронизированный текст (бесплатно, без ключа)
// ════════════════════════════════════════════════════════════════════════
function httpJson(opts) {
  return new Promise((resolve, reject) => {
    const lib = opts.protocol === 'http:' ? http : https;
    const req = lib.request(opts, res => {
      let data = '';
      res.on('data', c => { data += c; });
      res.on('end', () => {
        if (res.statusCode >= 400) return reject(new Error(`HTTP ${res.statusCode}`));
        try { resolve(JSON.parse(data)); } catch (e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.setTimeout(8000, () => { req.destroy(new Error('lyrics timeout')); });
    req.end();
  });
}

async function fetchLyrics(videoId, title, artist, durationSec) {
  // Проверим кеш
  const c = Q.lyricsGet.get(videoId);
  if (c) return { plain: c.plain || '', synced: c.synced || '', source: c.source || 'cache' };

  // Чистим заголовок от "(feat. ...)"
  const cleanTitle  = (title  || '').replace(/\([^)]*\)|\[[^\]]*\]/g, '').trim();
  const cleanArtist = (artist || '').replace(/[,&].*$/, '').trim();
  const qs = new URLSearchParams({
    track_name:  cleanTitle,
    artist_name: cleanArtist,
  });
  if (durationSec) qs.set('duration', String(durationSec));

  const opts = {
    protocol: 'https:',
    host:    'lrclib.net',
    path:    '/api/get?' + qs.toString(),
    method:  'GET',
    headers: { 'User-Agent': 'Musicbott/2.0 (+https://github.com)' },
  };
  let res;
  try { res = await httpJson(opts); }
  catch (_) {
    // fallback: search
    try {
      const sopt = { ...opts, path: '/api/search?' + new URLSearchParams({ track_name: cleanTitle, artist_name: cleanArtist }).toString() };
      const arr = await httpJson(sopt);
      res = (arr && arr[0]) || null;
    } catch (_) { res = null; }
  }
  const plain  = (res && res.plainLyrics)  || '';
  const synced = (res && res.syncedLyrics) || '';
  Q.lyricsPut.run(videoId, plain, synced, res ? 'lrclib' : 'none');
  return { plain, synced, source: res ? 'lrclib' : 'none' };
}

// ════════════════════════════════════════════════════════════════════════
//  СКОР РЕЦЕНЗИИ
//  6 критериев × 1..5 → сумма ∈ [6..30] → ×3 → [18..90]
// ════════════════════════════════════════════════════════════════════════
function clamp1to5(v) { v = parseInt(v, 10) || 0; return Math.max(1, Math.min(5, v)); }
function calcScore({ rarity, integrity, depth, execution, charisma, relevance }) {
  const r = clamp1to5(rarity), i = clamp1to5(integrity), d = clamp1to5(depth);
  const e = clamp1to5(execution), c = clamp1to5(charisma), x = clamp1to5(relevance);
  return (r + i + d + e + c + x) * 3; // 18..90
}

