// ── auth middleware
function auth(req, res, next) {
  const init = req.header('X-Tg-Init-Data') || req.query._initData || '';
  const data = parseInitData(init);
  if (!data) return res.status(401).json({ error: 'invalid_init_data' });
  const u = upsertUser({
    tg_id:      data.user.id,
    username:   data.user.username,
    first_name: data.user.first_name,
    photo_url:  data.user.photo_url || null,
  });
  if (u.is_banned) return res.status(403).json({ error: 'banned', reason: u.ban_reason || '' });
  req.user = u;
  req.tgUser = data.user;
  next();
}

function adminOnly(req, res, next) {
  if (!req.user) return res.status(401).json({ error: 'no_user' });
  if (!ADMIN_IDS.has(req.user.tg_id)) return res.status(403).json({ error: 'forbidden' });
  next();
}

