app.post('/api/reviews/:videoId', auth, (req, res) => {
  const { videoId } = req.params;
  if (!Q.trackById.get(videoId)) return res.status(404).json({ error: 'no_track' });
  const b = req.body || {};
  const grades = {
    rarity:    clamp1to5(b.rarity),
    integrity: clamp1to5(b.integrity),
    depth:     clamp1to5(b.depth),
    execution: clamp1to5(b.execution),
    charisma:  clamp1to5(b.charisma),
    relevance: clamp1to5(b.relevance),
  };
  const text = (b.review_text || '').toString().slice(0, 2000);
  const score = calcScore(grades);
  Q.upsertReview.run(req.user.id, videoId,
    grades.rarity, grades.integrity, grades.depth, grades.execution,
    grades.charisma, grades.relevance, score, text);
  res.json({ ok: true, score });
});

