const bot = new TelegramBot(BOT_TOKEN, { polling: true });

const WELCOME = (firstName) =>
  `🎧 <b>Привет, ${escapeHtml(firstName || 'друг')}!</b>\n\n` +
  `Это — музыкальный плеер прямо в Telegram.\n\n` +
  `• YouTube Music без ограничений\n` +
  `• Синхронизированный текст (караоке)\n` +
  `• Плейлисты, лайки, рецензии\n` +
  `• Кастомные профили\n\n` +
  `Нажми кнопку ниже, чтобы открыть приложение 👇`;

function escapeHtml(s){return String(s||'').replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}

function mainKb() {
  return {
    inline_keyboard: [
      [{ text: '🎧 Открыть плеер', web_app: { url: MINI_APP_URL } }],
      [{ text: '📚 Помощь', callback_data: 'help' }],
    ],
  };
}

bot.onText(/^\/start(?:\s+(.+))?$/, async (msg, match) => {
  const from = msg.from;
  upsertUser({ tg_id: from.id, username: from.username, first_name: from.first_name });
  try {
    await bot.sendMessage(msg.chat.id, WELCOME(from.first_name), {
      parse_mode: 'HTML', reply_markup: mainKb(),
    });
  } catch (e) { log.warn('sendMessage', e.message); }
});

bot.onText(/^\/help$/, async msg => {
  await bot.sendMessage(msg.chat.id,
    'Все функции — внутри Mini-App. Нажмите кнопку «Открыть плеер».',
    { reply_markup: mainKb() });
});

